// 1. Function to clean the HTML
function cleanWebContent(raw) {
  if (!raw || typeof raw !== 'string') return "";

  // Standardize common escape characters
  let text = raw
    .replace(/\\n/g, '\n')
    .replace(/\\r/g, '\n')
    .replace(/\\t/g, ' ')
    .replace(/\\"/g, '"');

  // A. REMOVE NOISY BLOCKS (Removes tags AND their contents)
  // This targets headers, footers, scripts, and navigation entirely.
  const noise = ['header', 'footer', 'nav', 'aside', 'script', 'style', 'noscript', 'head', 'form'];
  noise.forEach(tag => {
    const regex = new RegExp('<' + tag + '[\\s\\S]*?<\\/' + tag + '>', 'gi');
    text = text.replace(regex, ' ');
  });

  // B. PRESERVE URLs (Crucial Step)
  // Converts <a href="url">Text</a> into "Text [url]" before the tags are stripped.
  text = text.replace(/<a\s+(?:[^>]*?\s+)?href=(["'])(.*?)\1[^>]*?>([\s\S]*?)<\/a>/gi, (match, quote, url, linkText) => {
    const cleanLabel = linkText.replace(/<[^>]+>/g, '').trim(); // Remove nested tags like <span>
    return cleanLabel ? `${cleanLabel} [${url}]` : url;
  });

  // C. STRIP ALL REMAINING TAGS ONLY
  // This removes the <...> brackets but keeps the text inside.
  text = text.replace(/<[^>]+>/g, ' ');

  // D. DECODE HTML ENTITIES (e.g., &amp; -> &)
  const entities = { '&nbsp;':' ','&amp;':'&','&lt;':'<','&gt;':'>','&quot;':'"','&apos;':"'" };
  for (const [entity, replacement] of Object.entries(entities)) {
    text = text.replace(new RegExp(entity, 'g'), replacement);
  }

  // E. CLEANUP WHITESPACE
  return text
    .replace(/[ \t]+/g, ' ')     // Collapse multiple spaces
    .replace(/\n\s*\n/g, '\n\n') // Collapse multiple empty lines
    .trim();
}

// 2. n8n Logic: Get input and return the single cleaned item
const inputData = $input.first().json.data;
return [{
  data: cleanWebContent(inputData)
}];
